import { z } from "zod";

/**
 * The tenant-selectable theme presets. Each id MUST have a matching
 * `[data-theme="<id>"]` block in `app/themes.css` (generated by
 * `scripts/gen-themes.mjs`). Single source of truth for the settings schema
 * and the admin picker.
 *
 * `swatch` is only for the picker UI — three representative colours per mode so
 * the grid can preview a theme without applying it.
 */
export type ThemePresetId =
  | "modern-minimal"
  | "clean-slate"
  | "supabase"
  | "ocean-breeze"
  | "nature"
  | "claude"
  | "vintage-paper"
  | "amber-minimal"
  | "midnight-bloom"
  | "neo-brutalism";

export type ThemePreset = {
  id: ThemePresetId;
  label: string;
  description: string;
  swatch: { light: [string, string, string]; dark: [string, string, string] };
};

