export const DEFAULT_THEME_PRESET: ThemePresetId = "modern-minimal";

const IDS = THEME_PRESETS.map((p) => p.id) as [ThemePresetId, ...ThemePresetId[]];

export const themePresetSchema = z.enum(IDS);

export function isThemePresetId(value: unknown): value is ThemePresetId {
  return typeof value === "string" && IDS.includes(value as ThemePresetId);
}

export function getThemePreset(id: ThemePresetId): ThemePreset {
  return THEME_PRESETS.find((p) => p.id === id) ?? THEME_PRESETS[0];
}
